28	// newThreadedBtreeStoreIndexer returns a storage for cacher by adding locking over the two 2 data structures:
29	// * btree based storage for efficient LIST operation on prefix
30	// * map based indexer for retrieving values by index.
31	// This separation is used to allow independent snapshotting those two storages in the future.
32	// Intention is to utilize btree for its cheap snapshots that don't require locking if don't mutate data.
33	func newThreadedBtreeStoreIndexer(indexers cache.Indexers, degree int) *threadedStoreIndexer {
34		return &threadedStoreIndexer{
35			store:   newBtreeStore(degree),
36			indexer: newIndexer(indexers),
37		}
38	}
