68	func (si *threadedStoreIndexer) addOrUpdate(obj interface{}) error {
69		if obj == nil {
70			return fmt.Errorf("obj cannot be nil")
71		}
72		newElem, ok := obj.(*Element)
73		if !ok {
74			return fmt.Errorf("obj not a storeElement: %#v", obj)
75		}
76		si.lock.Lock()
77		defer si.lock.Unlock()
78		oldElem := si.store.addOrUpdateElem(newElem)
79		return si.indexer.updateElem(newElem.Key, oldElem, newElem)
80	}
81	
82	func (si *threadedStoreIndexer) Delete(obj interface{}) error {
83		storeElem, ok := obj.(*Element)
84		if !ok {
85			return fmt.Errorf("obj not a storeElement: %#v", obj)
86		}
87		si.lock.Lock()
88		defer si.lock.Unlock()
89		oldObj, existed := si.store.deleteElem(storeElem)
90		if !existed {
91			return nil
92		}
93		return si.indexer.updateElem(storeElem.Key, oldObj, nil)
94	}
